import{_ as d,o as a,c as e,a2 as s}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"命令与权限","description":"","frontmatter":{},"headers":[],"relativePath":"gtdungeonteam/commands.md","filePath":"gtdungeonteam/commands.md","lastUpdated":1783543150000}'),n={name:"gtdungeonteam/commands.md"};function o(p,t,l,i,c,r){return a(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="命令与权限" tabindex="-1">命令与权限 <a class="header-anchor" href="#命令与权限" aria-label="Permalink to &quot;命令与权限&quot;">​</a></h1><p>主命令：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtdungeonteam</span></span>
<span class="line"><span>/gdteam</span></span>
<span class="line"><span>/gdt</span></span></code></pre></div><p>普通玩家默认拥有 <code>gtdungeonteam.command</code>。管理命令需要 <code>gtdungeonteam.admin</code>。</p><h2 id="基础命令" tabindex="-1">基础命令 <a class="header-anchor" href="#基础命令" aria-label="Permalink to &quot;基础命令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/gdt</code></td><td>打开默认主界面</td></tr><tr><td><code>/gdt open &lt;界面&gt;</code></td><td>打开指定界面</td></tr><tr><td><code>/gdt help</code></td><td>查看全部帮助</td></tr><tr><td><code>/gdt help &lt;分类&gt;</code></td><td>查看某一类帮助</td></tr><tr><td><code>/gdt providers</code></td><td>查看副本适配器可用状态</td></tr><tr><td><code>/gdt status</code></td><td>查看插件状态，需要管理权限</td></tr><tr><td><code>/gdt reload</code></td><td>重载配置，需要管理权限</td></tr></tbody></table><p>帮助分类：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>basic</span></span>
<span class="line"><span>team</span></span>
<span class="line"><span>dungeon</span></span>
<span class="line"><span>rooms</span></span>
<span class="line"><span>ui</span></span>
<span class="line"><span>admin</span></span></code></pre></div><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gdt help team</span></span>
<span class="line"><span>/gdt help dungeon</span></span></code></pre></div><h2 id="打开界面" tabindex="-1">打开界面 <a class="header-anchor" href="#打开界面" aria-label="Permalink to &quot;打开界面&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gdt open main</span></span>
<span class="line"><span>/gdt open team</span></span>
<span class="line"><span>/gdt open invite</span></span>
<span class="line"><span>/gdt open applications</span></span>
<span class="line"><span>/gdt open requirements</span></span>
<span class="line"><span>/gdt open auction</span></span>
<span class="line"><span>/gdt open dungeons</span></span>
<span class="line"><span>/gdt open dungeon-detail</span></span>
<span class="line"><span>/gdt open rooms</span></span>
<span class="line"><span>/gdt open room-detail</span></span>
<span class="line"><span>/gdt open result</span></span></code></pre></div><p>如果当前 UI 引擎可用，会优先打开客户端 UI。不可用时打开原版 GUI。</p><h2 id="队伍命令" tabindex="-1">队伍命令 <a class="header-anchor" href="#队伍命令" aria-label="Permalink to &quot;队伍命令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/gdt team create</code></td><td>创建队伍</td></tr><tr><td><code>/gdt team invite &lt;玩家&gt;</code></td><td>邀请玩家</td></tr><tr><td><code>/gdt team invite</code></td><td>打开邀请列表</td></tr><tr><td><code>/gdt team accept</code></td><td>接受最近收到的邀请</td></tr><tr><td><code>/gdt team leave</code></td><td>离开队伍，队长使用时会解散队伍</td></tr><tr><td><code>/gdt team disband</code></td><td>解散队伍</td></tr><tr><td><code>/gdt team kick &lt;玩家&gt;</code></td><td>队长踢出队员</td></tr><tr><td><code>/gdt team public</code></td><td>设置为公开队伍</td></tr><tr><td><code>/gdt team private</code></td><td>设置为私密队伍</td></tr><tr><td><code>/gdt team applymode [on/off]</code></td><td>切换是否接收入队申请</td></tr><tr><td><code>/gdt team pvp [on/off]</code></td><td>切换队友伤害</td></tr><tr><td><code>/gdt team loot [on/off]</code></td><td>切换队伍掉落分配</td></tr><tr><td><code>/gdt team random [on/off]</code></td><td>同掉落分配开关</td></tr><tr><td><code>/gdt team info</code></td><td>查看当前队伍信息</td></tr></tbody></table><p><code>applymode</code>、<code>pvp</code>、<code>loot</code> 不写 <code>on/off</code> 时，会按当前状态取反。</p><p>可识别的开关值：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>on off</span></span>
<span class="line"><span>true false</span></span>
<span class="line"><span>yes no</span></span>
<span class="line"><span>1 0</span></span>
<span class="line"><span>enable disable</span></span>
<span class="line"><span>开 关</span></span>
<span class="line"><span>开启 关闭</span></span></code></pre></div><h2 id="队伍名称和介绍" tabindex="-1">队伍名称和介绍 <a class="header-anchor" href="#队伍名称和介绍" aria-label="Permalink to &quot;队伍名称和介绍&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gdt team rename &lt;名称&gt;</span></span>
<span class="line"><span>/gdt team name &lt;名称&gt;</span></span>
<span class="line"><span>/gdt team desc &lt;介绍&gt;</span></span>
<span class="line"><span>/gdt team description &lt;介绍&gt;</span></span>
<span class="line"><span>/gdt team intro &lt;介绍&gt;</span></span></code></pre></div><p>队伍名称是显示名，不是队伍 ID。公开房间、队伍详情、客户端 UI 显示的是队伍名称。</p><h2 id="入队申请" tabindex="-1">入队申请 <a class="header-anchor" href="#入队申请" aria-label="Permalink to &quot;入队申请&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/gdt team apply &lt;队伍ID&gt;</code></td><td>申请加入队伍</td></tr><tr><td><code>/gdt team applications</code></td><td>队长打开申请列表</td></tr><tr><td><code>/gdt team acceptapp &lt;玩家&gt;</code></td><td>同意申请</td></tr><tr><td><code>/gdt team rejectapp &lt;玩家&gt;</code></td><td>拒绝申请</td></tr><tr><td><code>/gdt team denyapp &lt;玩家&gt;</code></td><td>同拒绝申请</td></tr></tbody></table><p>如果玩家同时申请了多个队伍，其中一个队伍同意后，其他队伍再同意会失败，因为玩家已经有队伍了。</p><h2 id="入队条件" tabindex="-1">入队条件 <a class="header-anchor" href="#入队条件" aria-label="Permalink to &quot;入队条件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/gdt team req templates</code></td><td>查看服务器配置的条件模板</td></tr><tr><td><code>/gdt team req add &lt;模板&gt; &lt;比较符&gt; &lt;值&gt;</code></td><td>添加或覆盖入队条件</td></tr><tr><td><code>/gdt team req add &lt;模板&gt; &lt;值&gt;</code></td><td>使用模板默认比较符添加条件</td></tr><tr><td><code>/gdt team req remove &lt;模板&gt;</code></td><td>移除条件</td></tr><tr><td><code>/gdt team req clear</code></td><td>清空全部条件</td></tr><tr><td><code>/gdt team req list</code></td><td>查看当前队伍条件</td></tr></tbody></table><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gdt team req templates</span></span>
<span class="line"><span>/gdt team req add power &gt;= 5000</span></span>
<span class="line"><span>/gdt team req add level &gt;= 30</span></span>
<span class="line"><span>/gdt team req add job 战士</span></span>
<span class="line"><span>/gdt team req remove power</span></span></code></pre></div><p><code>job</code> 这类文本条件可以直接写中文。比较符不写时，使用配置模板里的 <code>default-operator</code>。</p><h2 id="公开房间" tabindex="-1">公开房间 <a class="header-anchor" href="#公开房间" aria-label="Permalink to &quot;公开房间&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/gdt rooms</code></td><td>打开公开房间界面</td></tr><tr><td><code>/gdt rooms list</code></td><td>聊天栏列出公开房间</td></tr><tr><td><code>/gdt rooms detail &lt;队伍ID&gt;</code></td><td>查看队伍详情</td></tr><tr><td><code>/gdt rooms join &lt;队伍ID&gt;</code></td><td>加入或申请队伍</td></tr><tr><td><code>/gdt rooms apply &lt;队伍ID&gt;</code></td><td>同 join</td></tr><tr><td><code>/gdt rooms quick</code></td><td>快速加入合适队伍</td></tr></tbody></table><p>公开房间详情页会显示队伍名、队长、介绍、目标副本、人数、入队条件。不要让玩家只看一个队伍 ID 就盲进，RPG 服推荐先看详情。</p><h2 id="副本命令" tabindex="-1">副本命令 <a class="header-anchor" href="#副本命令" aria-label="Permalink to &quot;副本命令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/gdt dungeon list</code></td><td>查看副本列表</td></tr><tr><td><code>/gdt dungeon open &lt;副本ID&gt;</code></td><td>从入口打开副本详情</td></tr><tr><td><code>/gdt dungeon detail &lt;副本ID&gt;</code></td><td>同 open</td></tr><tr><td><code>/gdt dungeon select &lt;副本ID&gt;</code></td><td>直接选择副本</td></tr><tr><td><code>/gdt dungeon start</code></td><td>队长开始副本</td></tr><tr><td><code>/gdt dungeon finish</code></td><td>测试用，标记成功结算</td></tr><tr><td><code>/gdt dungeon fail</code></td><td>测试用，标记失败结算</td></tr></tbody></table><p>大型服务器建议让 NPC、方块、菜单执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gdt dungeon open &lt;副本ID&gt;</span></span></code></pre></div><p>玩家先看到副本详情、难度、展示掉落，再由队长确认选择。</p><h2 id="竞拍命令" tabindex="-1">竞拍命令 <a class="header-anchor" href="#竞拍命令" aria-label="Permalink to &quot;竞拍命令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/gdt auction info</code></td><td>查看当前竞拍</td></tr><tr><td><code>/gdt auction current</code></td><td>同 info</td></tr><tr><td><code>/gdt auction open</code></td><td>打开竞拍界面</td></tr><tr><td><code>/gdt auction gui</code></td><td>同 open</td></tr><tr><td><code>/gdt bid &lt;金额&gt;</code></td><td>对当前物品出价</td></tr></tbody></table><p>每次有效出价后，如果配置了 <code>reset-seconds-on-bid</code>，倒计时会刷新到指定秒数。</p><h2 id="管理命令" tabindex="-1">管理命令 <a class="header-anchor" href="#管理命令" aria-label="Permalink to &quot;管理命令&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gdt reload</span></span>
<span class="line"><span>/gdt status</span></span></code></pre></div><p><code>/gdt reload</code> 会重载：</p><ul><li><code>config.yml</code></li><li><code>dungeons/</code></li><li><code>gui/</code></li><li><code>assets/</code></li><li><code>hud/</code></li><li><code>client-ui/</code></li><li>PaiUI 消息桥</li></ul><p>客户端 UI 改动后也执行这个命令。涉及跨服、数据库连接、插件加载顺序的问题，还是建议重启。</p><h2 id="权限" tabindex="-1">权限 <a class="header-anchor" href="#权限" aria-label="Permalink to &quot;权限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>权限</th><th>默认</th><th>说明</th></tr></thead><tbody><tr><td><code>gtdungeonteam.command</code></td><td>true</td><td>使用普通命令</td></tr><tr><td><code>gtdungeonteam.admin</code></td><td>op</td><td>使用 reload、status 等管理命令</td></tr></tbody></table><p>副本入口权限写在副本文件里：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">dungeon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  entry</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    permission</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gtdungeonteam.entry.forest&quot;</span></span></code></pre></div><p>这个权限不是固定节点，每个副本都可以单独设置。</p>`,50)])])}const m=d(n,[["render",o]]);export{h as __pageData,m as default};
